import React, { useState, useEffect } from 'react';
import api from '../services/authService';

interface Cerda {
  id: number;
  identificador_unico: string;
  nombre: string;
}

interface Verraco {
  id: number;
  identificador_unico: string;
  nombre: string;
}

interface Ciclo {
  id: number;
  cerda_identificador: string;
  cerda_nombre: string;
  fecha_inicio: string;
  numero_ciclo: number;
  estado: string;
}

const Reproduction: React.FC = () => {
  const [activeTab, setActiveTab] = useState('cycles');
  const [cerdas, setCerdas] = useState<Cerda[]>([]);
  const [verracos, setVerracos] = useState<Verraco[]>([]);
  const [ciclos, setCiclos] = useState<Ciclo[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [formType, setFormType] = useState('cycle');
  const [editingId, setEditingId] = useState<number | null>(null);

  const [cycleForm, setCycleForm] = useState({
    cerda_id: '',
    fecha_inicio: new Date().toISOString().split('T')[0]
  });

  const [serviceForm, setServiceForm] = useState({
    ciclo_id: '',
    cerda_id: '',
    verraco_id: '',
    fecha: new Date().toISOString().split('T')[0],
    hora: '',
    tipo: 'natural',
    numero_servicio: 1
  });

  const [birthForm, setBirthForm] = useState({
    gestacion_id: '',
    fecha_real: new Date().toISOString().split('T')[0],
    lechones_vivos: '',
    lechones_muertos: '',
    lechones_momificados: '',
    peso_promedio: '',
    duracion_minutos: '',
    complicaciones: ''
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [cerdasRes, verracosRes, ciclosRes] = await Promise.all([
        api.get('/reproduction/sows'),
        api.get('/reproduction/boars'),
        api.get('/reproduction/cycles')
      ]);

      setCerdas(cerdasRes.data);
      setVerracos(verracosRes.data);
      setCiclos(ciclosRes.data);
    } catch (error) {
      console.error('Error cargando datos reproductivos:', error);
    }
  };

  const handleCycleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const data = {
        ...cycleForm,
        cerda_id: parseInt(cycleForm.cerda_id)
      };

      if (editingId && formType === 'cycle') {
        await api.put(`/reproduction/cycles/${editingId}`, data);
      } else {
        await api.post('/reproduction/cycles', data);
      }

      resetForms();
      loadData();
    } catch (error) {
      console.error('Error guardando ciclo:', error);
      alert('Error guardando ciclo');
    }
  };

  const resetForms = () => {
    setShowForm(false);
    setEditingId(null);
    setCycleForm({
      cerda_id: '',
      fecha_inicio: new Date().toISOString().split('T')[0]
    });
    setServiceForm({
      ciclo_id: '',
      cerda_id: '',
      verraco_id: '',
      fecha: new Date().toISOString().split('T')[0],
      hora: '',
      tipo: 'natural',
      numero_servicio: 1
    });
  };

  const handleEditCycle = (ciclo: Ciclo) => {
    setCycleForm({
      cerda_id: ciclo.cerda_identificador || '',
      fecha_inicio: ciclo.fecha_inicio
    });
    setEditingId(ciclo.id);
    setFormType('cycle');
    setShowForm(true);
  };

  const handleDeleteCycle = async (id: number) => {
    if (window.confirm('¿Estás seguro de eliminar este ciclo?')) {
      try {
        await api.delete(`/reproduction/cycles/${id}`);
        loadData();
      } catch (error) {
        console.error('Error eliminando ciclo:', error);
        alert('Error eliminando ciclo');
      }
    }
  };

  const handleServiceSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const data = {
        ...serviceForm,
        ciclo_id: parseInt(serviceForm.ciclo_id),
        cerda_id: parseInt(serviceForm.cerda_id),
        verraco_id: parseInt(serviceForm.verraco_id),
        numero_servicio: parseInt(serviceForm.numero_servicio.toString())
      };

      if (editingId && formType === 'service') {
        await api.put(`/reproduction/services/${editingId}`, data);
      } else {
        await api.post('/reproduction/service', data);
      }

      resetForms();
      loadData();
    } catch (error) {
      console.error('Error guardando servicio:', error);
      alert('Error guardando servicio');
    }
  };

  const openForm = (type: string) => {
    setFormType(type);
    setShowForm(true);
  };

  const tabStyle = (tab: string) => ({
    padding: '12px 24px',
    border: 'none',
    backgroundColor: activeTab === tab ? '#007bff' : '#f8f9fa',
    color: activeTab === tab ? 'white' : '#333',
    cursor: 'pointer',
    borderRadius: '4px 4px 0 0',
    marginRight: '2px'
  });

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-3">
        <h1>Control Reproductivo</h1>
        <div>
          <button 
            className="btn btn-success"
            onClick={() => openForm('cycle')}
            style={{ marginRight: '10px' }}
          >
            Nuevo Ciclo
          </button>
          <button 
            className="btn btn-primary"
            onClick={() => openForm('service')}
          >
            Registrar Servicio
          </button>
        </div>
      </div>

      {/* Tabs */}
      <div style={{ marginBottom: '20px' }}>
        <button 
          style={tabStyle('cycles')}
          onClick={() => setActiveTab('cycles')}
        >
          Ciclos Reproductivos
        </button>
        <button 
          style={tabStyle('summary')}
          onClick={() => setActiveTab('summary')}
        >
          Resumen
        </button>
        <button 
          style={tabStyle('animals')}
          onClick={() => setActiveTab('animals')}
        >
          Reproductores
        </button>
      </div>

      {/* Formularios */}
      {showForm && (
        <div className="card mb-3">
          {formType === 'cycle' && (
            <div>
              <h3>{editingId && formType === 'cycle' ? '✏️ Editar Ciclo' : '➕ Nuevo Ciclo Reproductivo'}</h3>
              <form onSubmit={handleCycleSubmit}>
                <div className="grid grid-2">
                  <div className="form-group">
                    <label>Cerda:</label>
                    <select
                      className="form-control"
                      value={cycleForm.cerda_id}
                      onChange={(e) => setCycleForm({...cycleForm, cerda_id: e.target.value})}
                      required
                    >
                      <option value="">Seleccionar cerda</option>
                      {cerdas.map(cerda => (
                        <option key={cerda.id} value={cerda.id}>
                          {cerda.identificador_unico} - {cerda.nombre || 'Sin nombre'}
                        </option>
                      ))}
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Fecha de Inicio:</label>
                    <input
                      type="date"
                      className="form-control"
                      value={cycleForm.fecha_inicio}
                      onChange={(e) => setCycleForm({...cycleForm, fecha_inicio: e.target.value})}
                      required
                    />
                  </div>
                </div>
                <div style={{ display: 'flex', gap: '10px' }}>
                  <button type="submit" className="btn btn-success">
                    {editingId && formType === 'cycle' ? '💾 Actualizar' : '💾 Crear'} Ciclo
                  </button>
                  <button 
                    type="button" 
                    className="btn btn-secondary"
                    onClick={resetForms}
                  >
                    ❌ Cancelar
                  </button>
                </div>
              </form>
            </div>
          )}

          {formType === 'service' && (
            <div>
              <h3>{editingId && formType === 'service' ? '✏️ Editar Servicio' : '➕ Registrar Servicio'}</h3>
              <form onSubmit={handleServiceSubmit}>
                <div className="grid grid-3">
                  <div className="form-group">
                    <label>Ciclo Reproductivo:</label>
                    <select
                      className="form-control"
                      value={serviceForm.ciclo_id}
                      onChange={(e) => {
                        const cicloId = e.target.value;
                        const ciclo = ciclos.find(c => c.id.toString() === cicloId);
                        setServiceForm({
                          ...serviceForm, 
                          ciclo_id: cicloId,
                          cerda_id: ciclo ? ciclo.cerda_identificador : ''
                        });
                      }}
                      required
                    >
                      <option value="">Seleccionar ciclo</option>
                      {ciclos.filter(c => c.estado === 'activo').map(ciclo => (
                        <option key={ciclo.id} value={ciclo.id}>
                          Ciclo #{ciclo.numero_ciclo} - {ciclo.cerda_identificador}
                        </option>
                      ))}
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Cerda:</label>
                    <select
                      className="form-control"
                      value={serviceForm.cerda_id}
                      onChange={(e) => setServiceForm({...serviceForm, cerda_id: e.target.value})}
                      required
                    >
                      <option value="">Seleccionar cerda</option>
                      {cerdas.map(cerda => (
                        <option key={cerda.id} value={cerda.id}>
                          {cerda.identificador_unico} - {cerda.nombre || 'Sin nombre'}
                        </option>
                      ))}
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Verraco:</label>
                    <select
                      className="form-control"
                      value={serviceForm.verraco_id}
                      onChange={(e) => setServiceForm({...serviceForm, verraco_id: e.target.value})}
                      required
                    >
                      <option value="">Seleccionar verraco</option>
                      {verracos.map(verraco => (
                        <option key={verraco.id} value={verraco.id}>
                          {verraco.identificador_unico} - {verraco.nombre || 'Sin nombre'}
                        </option>
                      ))}
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Tipo de Servicio:</label>
                    <select
                      className="form-control"
                      value={serviceForm.tipo}
                      onChange={(e) => setServiceForm({...serviceForm, tipo: e.target.value})}
                    >
                      <option value="natural">Monta Natural</option>
                      <option value="artificial">Inseminación Artificial</option>
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Fecha:</label>
                    <input
                      type="date"
                      className="form-control"
                      value={serviceForm.fecha}
                      onChange={(e) => setServiceForm({...serviceForm, fecha: e.target.value})}
                      required
                    />
                  </div>
                  <div className="form-group">
                    <label>Hora:</label>
                    <input
                      type="time"
                      className="form-control"
                      value={serviceForm.hora}
                      onChange={(e) => setServiceForm({...serviceForm, hora: e.target.value})}
                    />
                  </div>
                  <div className="form-group">
                    <label>Número de Servicio:</label>
                    <input
                      type="number"
                      className="form-control"
                      value={serviceForm.numero_servicio}
                      onChange={(e) => setServiceForm({...serviceForm, numero_servicio: parseInt(e.target.value)})}
                      min="1"
                      max="3"
                    />
                  </div>
                </div>
                <div style={{ display: 'flex', gap: '10px' }}>
                  <button type="submit" className="btn btn-success">
                    {editingId && formType === 'service' ? '💾 Actualizar' : '💾 Registrar'} Servicio
                  </button>
                  <button 
                    type="button" 
                    className="btn btn-secondary"
                    onClick={resetForms}
                  >
                    ❌ Cancelar
                  </button>
                </div>
              </form>
            </div>
          )}
        </div>
      )}

      {/* Contenido de las tabs */}
      {activeTab === 'cycles' && (
        <div className="card">
          <h3>Ciclos Reproductivos ({ciclos.length})</h3>
          {ciclos.length > 0 ? (
            <table className="table">
              <thead>
                <tr>
                  <th>Cerda</th>
                  <th>Nombre</th>
                  <th>Ciclo #</th>
                  <th>Fecha Inicio</th>
                  <th>Estado</th>
                  <th>Acciones</th>
                </tr>
              </thead>
              <tbody>
                {ciclos.map(ciclo => (
                  <tr key={ciclo.id}>
                    <td>{ciclo.cerda_identificador}</td>
                    <td>{ciclo.cerda_nombre || '-'}</td>
                    <td>
                      <span style={{
                        padding: '4px 8px',
                        borderRadius: '12px',
                        backgroundColor: '#007bff',
                        color: 'white',
                        fontSize: '12px'
                      }}>
                        #{ciclo.numero_ciclo}
                      </span>
                    </td>
                    <td>{new Date(ciclo.fecha_inicio).toLocaleDateString()}</td>
                    <td>
                      <span className={`badge ${
                        ciclo.estado === 'activo' ? 'badge-success' : 'badge-danger'
                      }`}>
                        {ciclo.estado === 'activo' ? '✅ Activo' : '❌ Inactivo'}
                      </span>
                    </td>
                    <td>
                      <div className="action-buttons">
                        <button 
                          className="btn btn-warning btn-sm"
                          onClick={() => handleEditCycle(ciclo)}
                          title="Editar ciclo"
                        >
                          ✏️
                        </button>
                        <button 
                          className="btn btn-danger btn-sm"
                          onClick={() => handleDeleteCycle(ciclo.id)}
                          title="Eliminar ciclo"
                        >
                          🗑️
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <div style={{ textAlign: 'center', padding: '40px', color: '#666' }}>
              <div style={{ fontSize: '48px', marginBottom: '15px' }}>🔄</div>
              <p>No hay ciclos reproductivos registrados</p>
            </div>
          )}
        </div>
      )}

      {activeTab === 'summary' && (
        <div className="grid grid-2">
          <div className="card">
            <h3>Estadísticas del Mes</h3>
            <div style={{ padding: '20px', textAlign: 'center' }}>
              <div style={{ fontSize: '48px', marginBottom: '15px' }}>📊</div>
              <p style={{ color: '#666' }}>Estadísticas reproductivas en desarrollo...</p>
            </div>
          </div>
          <div className="card">
            <h3>Próximos Eventos</h3>
            <div style={{ padding: '20px', textAlign: 'center' }}>
              <div style={{ fontSize: '48px', marginBottom: '15px' }}>📅</div>
              <p style={{ color: '#666' }}>Calendario reproductivo en desarrollo...</p>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'animals' && (
        <div className="grid grid-2">
          <div className="card">
            <h3>🐷 Cerdas Reproductoras ({cerdas.length})</h3>
            {cerdas.length > 0 ? (
              <div>
                {cerdas.map(cerda => (
                  <div key={cerda.id} style={{
                    padding: '12px',
                    margin: '8px 0',
                    backgroundColor: '#f8f9fa',
                    border: '1px solid #dee2e6',
                    borderRadius: '4px'
                  }}>
                    <div style={{ fontWeight: 'bold' }}>{cerda.identificador_unico}</div>
                    <div style={{ fontSize: '14px', color: '#666' }}>
                      {cerda.nombre || 'Sin nombre'}
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div style={{ textAlign: 'center', padding: '40px', color: '#666' }}>
                <p>No hay cerdas reproductoras registradas</p>
              </div>
            )}
          </div>

          <div className="card">
            <h3>🐗 Verracos ({verracos.length})</h3>
            {verracos.length > 0 ? (
              <div>
                {verracos.map(verraco => (
                  <div key={verraco.id} style={{
                    padding: '12px',
                    margin: '8px 0',
                    backgroundColor: '#f8f9fa',
                    border: '1px solid #dee2e6',
                    borderRadius: '4px'
                  }}>
                    <div style={{ fontWeight: 'bold' }}>{verraco.identificador_unico}</div>
                    <div style={{ fontSize: '14px', color: '#666' }}>
                      {verraco.nombre || 'Sin nombre'}
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div style={{ textAlign: 'center', padding: '40px', color: '#666' }}>
                <p>No hay verracos registrados</p>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Reproduction;
